select

from precise_client_employee



		and name = #{name,jdbcType=VARCHAR}


		and id = #{id,jdbcType=CHAR}


		and (cellphone = #{cellphone1,jdbcType=VARCHAR} OR cellphone1 = #{cellphone1,jdbcType=VARCHAR})

select A.name, A.is_verified, A.type, A.gender, A.wechat, A.wechat1, A.cellphone, A.cellphone1, A.id, A.financial_body_pk, A.head_photo, A.employee_area, A.employee_county, A.detail_address, A.comment, A.self_photo, A.other_photo, A.binding_status, A.binding_count, A.pk, A.create_user, A.update_user, A.create_time, A.update_time, B.client_short_name AS financial_body_name from precise_client_employee A LEFT JOIN client B ON A.financial_body_pk = B.pk
and A.employee_area = #{params.bo.employee_area,jdbcType=VARCHAR}
and A.name LIKE CONCAT('%',#{params.bo.name,jdbcType=VARCHAR},'%')
and (A.wechat LIKE CONCAT('%',#{params.bo.wechat,jdbcType=VARCHAR},'%') OR A.wechat1 LIKE CONCAT('%',#{params.bo.wechat,jdbcType=VARCHAR},'%'))
and (A.cellphone LIKE CONCAT('%',#{params.bo.cellphone,jdbcType=VARCHAR},'%') OR A.cellphone1 LIKE CONCAT('%',#{params.bo.cellphone,jdbcType=VARCHAR},'%'))
and A.binding_status in
#{item}
and A.is_verified in
#{item}
